import os
import logging
from typing import List, Dict, Any
from langchain.vectorstores import Chroma
from langchain.embeddings import HuggingFaceEmbeddings
from langchain.chains import RetrievalQA
from langchain.llms import OpenAI
from langchain.text_splitter import RecursiveCharacterTextSplitter
from langchain.docstore.document import Document
from langchain.prompts import PromptTemplate
import json

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SecureRAGSystem:
    def __init__(self, vector_store_path: str = "chroma_db", embedding_model: str = "all-MiniLM-L6-v2"):
        self.vector_store_path = vector_store_path
        self.embeddings = HuggingFaceEmbeddings(model_name=embedding_model)
        self.vector_store = None
        self.qa_chain = None
        
    def load_documents(self, documents: List[Dict[str, Any]]):
        """Load documents into vector database"""
        try:
            # Convert documents to LangChain format
            langchain_docs = []
            for doc in documents:
                langchain_docs.append(Document(
                    page_content=doc.get('content', ''),
                    metadata=doc.get('metadata', {})
                ))
            
            # Create vector store
            self.vector_store = Chroma(
                collection_name="company_knowledge",
                embedding_function=self.embeddings,
                persist_directory=self.vector_store_path
            )
            
            # Add documents to vector store
            self.vector_store.add_documents(langchain_docs)
            logger.info(f"Loaded {len(documents)} documents into vector store")
            
        except Exception as e:
            logger.error(f"Error loading documents: {str(e)}")
            raise
    
    def create_qa_chain(self, llm_model: str = "gpt-3.5-turbo", temperature: float = 0.3):
        """Create retrieval QA chain"""
        try:
            # Initialize LLM
            llm = OpenAI(
                model_name=llm_model,
                temperature=temperature,
                openai_api_key=os.getenv('OPENAI_API_KEY')
            )
            
            # Create prompt template
            template = """
            You are an internal company knowledge base assistant. 
            Use the following pieces of context to answer the question at the end. 
            If you don't know the answer, just say that you don't know, don't try to make up an answer.
            
            Context:
            {context}
            
            Question: {question}
            Answer:
            """
            
            prompt = PromptTemplate(
                template=template,
                input_variables=["context", "question"]
            )
            
            # Create retrieval chain
            self.qa_chain = RetrievalQA.from_chain_type(
                llm=llm,
                chain_type="stuff",
                retriever=self.vector_store.as_retriever(),
                prompt=prompt,
                return_source_documents=True
            )
            
        except Exception as e:
            logger.error(f"Error creating QA chain: {str(e)}")
            raise
    
    def query(self, question: str) -> Dict[str, Any]:
        """Process user query and return answer with sources"""
        try:
            if not self.qa_chain:
                raise ValueError("QA chain not initialized. Call create_qa_chain first.")
            
            # Get answer
            result = self.qa_chain({"query": question})
            
            # Format response
            response = {
                "question": question,
                "answer": result["result"],
                "sources": []
            }
            
            # Add source documents
            for doc in result.get("source_documents", []):
                response["sources"].append({
                    "content": doc.page_content,
                    "metadata": doc.metadata
                })
            
            return response
            
        except Exception as e:
            logger.error(f"Error processing query: {str(e)}")
            raise

